"""
Runtime resource profiles for constraining hardware usage.
Enables running larger models on smaller hardware through intelligent resource allocation.
"""
import os
import psutil
from dataclasses import dataclass
from typing import Dict, Any, Optional
from enum import Enum

class ResourceLevel(Enum):
    """Resource usage levels"""
    MINIMAL = 25     # Ultra-conservative for very constrained hardware
    BALANCED = 50    # Balanced approach for typical hardware
    AGGRESSIVE = 75  # High utilization for capable hardware
    MAXIMUM = 100    # Full resource utilization

@dataclass
class ResourceProfile:
    """Resource constraints and parameters for a specific usage level"""
    level: ResourceLevel
    num_threads: int
    max_context_tokens: int
    step_tokens: int           # Tokens to generate per slice
    slice_sleep_ms: int        # Sleep between generation slices
    memory_limit_mb: Optional[int]
    description: str

class ResourceProfileManager:
    """
    Manages resource profiles and hardware detection.
    Provides resource constraints based on available hardware and user preference.
    """

    def __init__(self):
        self.hardware_info = self._detect_hardware()
        self.profiles = self._create_profiles()

    def _detect_hardware(self) -> Dict[str, Any]:
        """Detect available hardware resources"""
        return {
            'cpu_cores': psutil.cpu_count(logical=True),
            'physical_cores': psutil.cpu_count(logical=False),
            'memory_gb': psutil.virtual_memory().total / (1024**3),
            'available_memory_gb': psutil.virtual_memory().available / (1024**3)
        }

    def _create_profiles(self) -> Dict[ResourceLevel, ResourceProfile]:
        """Create resource profiles based on detected hardware"""
        cpu_cores = self.hardware_info['cpu_cores']
        memory_gb = self.hardware_info['memory_gb']

        profiles = {
            ResourceLevel.MINIMAL: ResourceProfile(
                level=ResourceLevel.MINIMAL,
                num_threads=1,
                max_context_tokens=3072,  # Increased for expanded system prompt (650 tokens) + tool results + response
                step_tokens=16,
                slice_sleep_ms=50,
                memory_limit_mb=int(memory_gb * 1024 * 0.2),  # 20% of total memory
                description="Ultra-conservative for very constrained hardware (2GB+ RAM, 2+ cores)"
            ),

            ResourceLevel.BALANCED: ResourceProfile(
                level=ResourceLevel.BALANCED,
                num_threads=max(2, cpu_cores // 2),
                max_context_tokens=5120,  # Increased to handle tool workflows comfortably
                step_tokens=32,
                slice_sleep_ms=30,
                memory_limit_mb=int(memory_gb * 1024 * 0.4),  # 40% of total memory
                description="Balanced approach for typical hardware (4GB+ RAM, 4+ cores)"
            ),

            ResourceLevel.AGGRESSIVE: ResourceProfile(
                level=ResourceLevel.AGGRESSIVE,
                num_threads=max(4, cpu_cores - 2),
                max_context_tokens=8192,  # Keep at 8K for good performance
                step_tokens=48,
                slice_sleep_ms=20,
                memory_limit_mb=int(memory_gb * 1024 * 0.6),  # 60% of total memory
                description="High utilization for capable hardware (8GB+ RAM, 6+ cores)"
            ),

            ResourceLevel.MAXIMUM: ResourceProfile(
                level=ResourceLevel.MAXIMUM,
                num_threads=cpu_cores,
                max_context_tokens=16384,  # Full context window for complex tasks
                step_tokens=64,
                slice_sleep_ms=10,
                memory_limit_mb=int(memory_gb * 1024 * 0.8),  # 80% of total memory
                description="Full resource utilization (16GB+ RAM, 8+ cores)"
            )
        }

        return profiles

    def get_profile(self, level: ResourceLevel) -> ResourceProfile:
        """Get resource profile for specified level"""
        return self.profiles[level]

    def get_profile_by_percentage(self, percentage: int) -> ResourceProfile:
        """Get resource profile by percentage (1-75% for dynamic control, plus fixed presets)"""

        # Handle fixed preset modes
        if percentage == 25:
            return self.get_profile(ResourceLevel.MINIMAL)
        elif percentage == 50:
            return self.get_profile(ResourceLevel.BALANCED)
        elif percentage == 75:
            return self.get_profile(ResourceLevel.AGGRESSIVE)
        elif percentage == 100:
            return self.get_profile(ResourceLevel.MAXIMUM)

        # Handle dynamic range (1-74%)
        if not (1 <= percentage <= 75):
            raise ValueError(f"Invalid percentage {percentage}. Must be between 1-75% or use presets 25%, 50%, 75%, 100%")

        # Generate dynamic profile for 1-75% range
        return self._create_dynamic_profile(percentage)

    def _create_dynamic_profile(self, percentage: int) -> ResourceProfile:
        """Create a dynamic resource profile for any percentage (1-75%)"""
        cpu_cores = self.hardware_info['cpu_cores']
        memory_gb = self.hardware_info['memory_gb']

        # Calculate scaling factor (0.01 to 0.75)
        scaling_factor = percentage / 100.0

        # Dynamic calculations based on scaling factor
        num_threads = max(1, min(cpu_cores, int(cpu_cores * scaling_factor * 1.2)))

        # Context tokens: scale from 3072 to 10240 (expanded range for tool workflows)
        base_context = 3072  # Minimum to fit expanded system prompt + tool results + response
        max_context = 10240  # Higher ceiling for complex tool chains
        max_context_tokens = int(base_context + (max_context - base_context) * scaling_factor)

        # Step tokens: scale from 16 to 64 (higher minimum for better responses)
        step_tokens = max(16, int(16 + (64 - 16) * scaling_factor))

        # Sleep time: higher percentage = less sleep (better performance)
        slice_sleep_ms = max(10, int(100 - (90 * scaling_factor)))

        # Memory limit: scale based on percentage
        memory_limit_mb = int(memory_gb * 1024 * scaling_factor * 0.8)  # Max 80% of total at 100%

        # Create description
        if percentage <= 10:
            description = f"Ultra-minimal resources ({percentage}%) - Very constrained mode"
        elif percentage <= 30:
            description = f"Low resources ({percentage}%) - Conservative usage"
        elif percentage <= 60:
            description = f"Moderate resources ({percentage}%) - Balanced usage"
        else:
            description = f"High resources ({percentage}%) - Performance-focused"

        return ResourceProfile(
            level=ResourceLevel.BALANCED,  # Use BALANCED as default for dynamic profiles
            num_threads=num_threads,
            max_context_tokens=max_context_tokens,
            step_tokens=step_tokens,
            slice_sleep_ms=slice_sleep_ms,
            memory_limit_mb=memory_limit_mb,
            description=description
        )

    def recommend_profile(self) -> ResourceProfile:
        """Recommend appropriate profile based on available hardware"""
        memory_gb = self.hardware_info['memory_gb']
        cpu_cores = self.hardware_info['cpu_cores']

        if memory_gb < 3 or cpu_cores < 3:
            return self.get_profile(ResourceLevel.MINIMAL)
        elif memory_gb < 6 or cpu_cores < 5:
            return self.get_profile(ResourceLevel.BALANCED)
        elif memory_gb < 12 or cpu_cores < 7:
            return self.get_profile(ResourceLevel.AGGRESSIVE)
        else:
            return self.get_profile(ResourceLevel.MAXIMUM)

    def get_ollama_params(self, profile: ResourceProfile) -> Dict[str, Any]:
        """Convert resource profile to Ollama/llama.cpp parameters"""
        return {
            'num_thread': profile.num_threads,
            'num_ctx': profile.max_context_tokens,
            # Additional parameters that can be set when available
            'num_predict': profile.step_tokens,  # For single-shot generation
            # Memory-related options (when supported)
            'numa': False,  # Disable NUMA for consistency
        }

    def check_memory_usage(self) -> Dict[str, float]:
        """Check current memory usage"""
        memory = psutil.virtual_memory()
        return {
            'total_gb': memory.total / (1024**3),
            'available_gb': memory.available / (1024**3),
            'used_percent': memory.percent,
            'free_percent': 100 - memory.percent
        }

    def is_profile_feasible(self, profile: ResourceProfile) -> tuple[bool, str]:
        """Check if a profile is feasible with current hardware"""
        memory_info = self.check_memory_usage()

        # Check if requested memory limit is reasonable
        required_memory_gb = profile.memory_limit_mb / 1024 if profile.memory_limit_mb else 0
        available_memory_gb = memory_info['available_gb']

        if required_memory_gb > available_memory_gb * 0.9:  # Leave 10% buffer
            return False, f"Insufficient memory: need {required_memory_gb:.1f}GB, have {available_memory_gb:.1f}GB available"

        # Check CPU cores
        if profile.num_threads > self.hardware_info['cpu_cores']:
            return False, f"Insufficient CPU cores: need {profile.num_threads}, have {self.hardware_info['cpu_cores']}"

        return True, "Profile is feasible"

    def get_hardware_summary(self) -> str:
        """Get human-readable hardware summary"""
        hw = self.hardware_info
        memory_info = self.check_memory_usage()

        return f"""Hardware Summary:
  CPU: {hw['physical_cores']} physical cores, {hw['cpu_cores']} logical cores
  Memory: {memory_info['total_gb']:.1f}GB total, {memory_info['available_gb']:.1f}GB available ({memory_info['free_percent']:.1f}% free)
  Recommended Profile: {self.recommend_profile().level.name} ({self.recommend_profile().level.value}%)"""

# Global instance for easy access
resource_manager = ResourceProfileManager()
